package com.example.demo.models;import jakarta.persistence.*;import lombok.*;import java.math.BigDecimal;import java.time.LocalDateTime;import java.util.*;
@Entity @Table(name="devoluciones") @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder public class Devolucion{@Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@ManyToOne(fetch=FetchType.LAZY,optional=false)@JoinColumn(name="venta_id")private Venta venta;@Column(nullable=false)private LocalDateTime fecha;@Column(nullable=false)private String motivo;@Column(nullable=false,precision=14,scale=2)@Builder.Default private BigDecimal total=BigDecimal.ZERO;@Enumerated(EnumType.STRING)@Column(name="forma_reintegro",nullable=false)private FormaReintegro formaReintegro;@ManyToOne(fetch=FetchType.LAZY)@JoinColumn(name="usuario_id")private Persona usuario;@OneToMany(mappedBy="devolucion",cascade=CascadeType.ALL,orphanRemoval=true)@Builder.Default private List<ItemDevolucion> items=new ArrayList<>();public void agregar(ItemDevolucion i){items.add(i);i.setDevolucion(this);total=total.add(i.getSubtotal());}public enum FormaReintegro{EFECTIVO,SALDO_A_FAVOR,SIN_REINTEGRO}}
